class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        const long long MOD = 1'000'000'007;
        vector<long long> fact(n + 1), invFact(n + 1);
        fact[0] = 1;
        for (int i = 1; i <= n; ++i) fact[i] = fact[i - 1] * i % MOD;
        invFact[n] = powMod(fact[n], MOD - 2, MOD);
        for (int i = n - 1; i >= 0; --i) invFact[i] = invFact[i + 1] * (i + 1) % MOD;

        long long res = 0;
        for (int k = 1; k <= min(x, n); ++k) {
            long long term = powMod(y, k, MOD) * C(x, k, fact, invFact, MOD) % MOD;
            term = term * stirling(n, k, fact, invFact, MOD) % MOD;
            res = (res + term) % MOD;
        }
        return static_cast<int>(res);
    }

private:
    long long powMod(long long a, long long b, long long mod) {
        long long res = 1;
        a %= mod;
        while (b) {
            if (b & 1) res = res * a % mod;
            a = a * a % mod;
            b >>= 1;
        }
        return res;
    }

    long long C(int n, int k, const vector<long long>& fact, const vector<long long>& invFact, long long MOD) {
        if (k < 0 || k > n) return 0;
        return fact[n] * invFact[k] % MOD * invFact[n - k] % MOD;
    }

    long long stirling(int n, int k, const vector<long long>& fact, const vector<long long>& invFact, long long MOD) {
        long long res = 0;
        for (int j = 0; j <= k; ++j) {
            long long sign = (j & 1) ? -1 : 1;
            long long term = C(k, j, fact, invFact, MOD) * powMod(k - j, n, MOD) % MOD;
            res = (res + sign * term + MOD) % MOD;
        }
        return res * invFact[k] % MOD;
    }
};
```
